// claim-office.spec.ts
import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("quotes: basics", () => {
    it.todo("should return premium 5 for a quote with an empty item list (processing fee only)");
    it.todo("should return premium 115 for a single sword (100 base + 10% first-insurance + 5 fee)");
    it.todo("should return premium 71 for a single amulet (60 base)");
    it.todo("should return premium 93 for a single staff (80 base)");
    it.todo("should return premium 49 for a single potion (40 base)");
    it.todo("should return one result per step in the scenario");
  });

  describe("quotes: components and block", () => {
    it.todo("should return premium 33 for a single rune (25 base, final premium rounded up)");
    it.todo("should return premium 60 for 2 runes (50 base, no block)");
    it.todo("should return premium 71 for exactly 3 runes (block rate of 60 base)");
    it.todo("should return premium 115 for 4 runes (100 base, block requires exactly 3)");
    it.todo("should return premium 198 for 7 runes (175 base, no block)");
    it.todo("should return premium 88 for 2 runes and 1 moonstone (75 base, no block across types)");
    it.todo("should return premium 137 for 3 runes and 3 moonstones (two blocks, 120 base)");
  });

  describe("quotes: item modifiers", () => {
    it.todo("should add 50% of the item base premium for a cursed item (cursed sword -> 165)");
    it.todo("should add 30% of the item base premium for enchantment level 5 or higher (sword ench 5 -> 145)");
  });

  describe("quotes: policy modifiers", () => {
    it.todo("should subtract 20% loyalty discount for customers with 2 or more years (sword, 2 years -> 95)");
    it.todo("should subtract 15% follow-up discount on each quote after the first in the scenario (second sword quote -> 100)");
  });

  describe("quotes: integration examples", () => {
    it.todo("should return premium 165 for a newcomer with a cursed steel sword of enchantment 3");
    it.todo("should return premium 160 for a 3-year customer's second quote with a cursed steel sword of enchantment 7");
  });

  describe("claims: payouts", () => {
    it.todo("should pay damage minus 100 deductible for a standard item (steel sword ench 3, damage 500 -> payout 400)");
    it.todo("should pay 100 for a rune damaged at 200");
    it.todo("should reimburse 50% of the damage before deductible for enchantment 8 or higher (steel sword ench 9, damage 1000 -> payout 400)");
    it.todo("should reimburse the full damage minus deductible for dragon material below enchantment 8 (dragon sword ench 5, damage 800 -> payout 700)");
    it.todo("should apply the 50% rule when both dragon material and enchantment 8+ apply (dragon sword ench 9, damage 1000 -> payout 400)");
    it.todo("should round the final payout down to a whole G (steel sword ench 9, damage 999 -> payout 399)");
  });

  describe("claims: deductible per damaged item", () => {
    it.todo("should apply the deductible once per damaged item (sword damage 500 + amulet damage 300 -> payout 600)");
    it.todo("should apply a separate deductible to each damage entry of the same type (two insured swords, two sword damage entries)");
  });

  describe("claims: payout cap", () => {
    it.todo("should report remainingCap as twice the insurance sum minus the payout (sword policy, claim 1500 -> payout 1400, remainingCap 600)");
    it.todo("should reduce the payout to the remaining cap on a later claim (second 1500 claim -> payout 600, remainingCap 0)");
    it.todo("should compute the cap from unmodified insurance values of all items (two swords -> cap 4000)");
  });

  describe("errors", () => {
    it.todo("should throw for an unknown item type in a quote (e.g. broomstick)");
    it.todo("should throw for a damage entry whose item type is not covered by the policy");
    it.todo("should throw when more damage entries of a type are claimed than items of that type are covered");
    it.todo("should throw for a negative damage amount");
  });
});
